#include<bits/stdc++.h>
using namespace std;
long long du[100005], u, v, n, x = 1, mod = 1e9;
int main() {
	cin >> n;
	for (int i = 1; i <= n - 1; i++) {
		cin >> u >> v;
		du[u]++;
		du[v]++;
	}
	for (int i = n - 1; i > 0; i--) {
		while (du[i]-1 > 0) {
			x = (du[i]-1) * x % mod;
			du[i]--;
		}
	}
	if (n <= 1) cout << 1;
	else cout << (2 * n - 2)*x % mod;
}
